const getAncestors = `-- name: GetAncestors :many
WITH RECURSIVE ancestors AS (
  SELECT links.id, links.source_id, links.target_id, links.type, 0 as depth
  FROM links
  WHERE links.target_id = $1 AND links.deleted_at IS NULL

  UNION ALL

  SELECT l.id, l.source_id, l.target_id, l.type, a.depth + 1
  FROM links l
  INNER JOIN ancestors a ON l.target_id = a.source_id
  WHERE l.deleted_at IS NULL AND a.depth < 10
)
SELECT ancestors.source_id as item_id, ancestors.type as link_type, ancestors.depth
FROM ancestors
ORDER BY ancestors.depth, ancestors.item_id
`

type GetAncestorsRow struct {
	ItemID   pgtype.UUID `db:"item_id" json:"item_id"`
	LinkType string      `db:"link_type" json:"link_type"`
	Depth    int32       `db:"depth" json:"depth"`
}

func (q *Queries) GetAncestors(ctx context.Context, targetID pgtype.UUID) ([]GetAncestorsRow, error) {
	rows, err := q.db.Query(ctx, getAncestors, targetID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []GetAncestorsRow{}
	for rows.Next() {
		var i GetAncestorsRow
		if err := rows.Scan(&i.ItemID, &i.LinkType, &i.Depth); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

