const getOrphanItems = `-- name: GetOrphanItems :many
SELECT i.id, i.project_id, i.title, i.description, i.type, i.status, i.priority, i.metadata, i.created_at, i.updated_at, i.deleted_at
FROM items i
WHERE i.project_id = $1
  AND i.deleted_at IS NULL
  AND NOT EXISTS (
    SELECT 1 FROM links l1 WHERE l1.source_id = i.id AND l1.deleted_at IS NULL
  )
  AND NOT EXISTS (
    SELECT 1 FROM links l2 WHERE l2.target_id = i.id AND l2.deleted_at IS NULL
  )
ORDER BY i.created_at DESC
`

type GetOrphanItemsRow struct {
	ID          pgtype.UUID      `db:"id" json:"id"`
	ProjectID   pgtype.UUID      `db:"project_id" json:"project_id"`
	Title       string           `db:"title" json:"title"`
	Description pgtype.Text      `db:"description" json:"description"`
	Type        string           `db:"type" json:"type"`
	Status      string           `db:"status" json:"status"`
	Priority    pgtype.Int4      `db:"priority" json:"priority"`
	Metadata    []byte           `db:"metadata" json:"metadata"`
	CreatedAt   pgtype.Timestamp `db:"created_at" json:"created_at"`
	UpdatedAt   pgtype.Timestamp `db:"updated_at" json:"updated_at"`
	DeletedAt   pgtype.Timestamp `db:"deleted_at" json:"deleted_at"`
}

func (q *Queries) GetOrphanItems(ctx context.Context, projectID pgtype.UUID) ([]GetOrphanItemsRow, error) {
	rows, err := q.db.Query(ctx, getOrphanItems, projectID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []GetOrphanItemsRow{}
	for rows.Next() {
		var i GetOrphanItemsRow
		if err := rows.Scan(
			&i.ID,
			&i.ProjectID,
			&i.Title,
			&i.Description,
			&i.Type,
			&i.Status,
			&i.Priority,
			&i.Metadata,
			&i.CreatedAt,
			&i.UpdatedAt,
			&i.DeletedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

